73					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
74					Rules:      []rbacv1.PolicyRule{{Verbs: []string{"get"}}},
75				},
76				fetched: &rbacv1.ClusterRole{
77					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
78					Rules:      []rbacv1.PolicyRule{{Verbs: []string{"get"}}},
79				},
80				wantChanged: false,
81			},
82			{
83				name: "ClusterRole rules different",
84				desired: &rbacv1.ClusterRole{
85					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
86					Rules:      []rbacv1.PolicyRule{{Verbs: []string{"get"}, APIGroups: []string{""}}},
87				},
88				fetched: &rbacv1.ClusterRole{
89					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
90					Rules:      []rbacv1.PolicyRule{{Verbs: []string{"list"}}},
91				},
92				wantChanged: true,
93			},
94			{
95				name: "matching ClusterRoleBinding identical",
96				desired: &rbacv1.ClusterRoleBinding{
97					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
98					RoleRef:    rbacv1.RoleRef{APIGroup: "rbac", Kind: "ClusterRole", Name: "x"},
99					Subjects:   []rbacv1.Subject{{Kind: "ServiceAccount", Name: "y", Namespace: "z"}},
100				},
101				fetched: &rbacv1.ClusterRoleBinding{
102					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
103					RoleRef:    rbacv1.RoleRef{APIGroup: "rbac", Kind: "ClusterRole", Name: "x"},
104					Subjects:   []rbacv1.Subject{{Kind: "ServiceAccount", Name: "y", Namespace: "z"}},
105				},
106				wantChanged: false,
107			},
108			{
109				name: "Deployment labels different",
110				desired: func() *appsv1.Deployment {
111					d := baseDeployment(1, "img")
112					d.Labels = map[string]string{"a": "1"}
113					return d
114				}(),
115				fetched: func() *appsv1.Deployment {
116					d := baseDeployment(1, "img")
117					d.Labels = map[string]string{"a": "2"}
118					return d
119				}(),
120				wantChanged: true,
121			},
122			{
123				name: "ConfigMap identical",
124				desired: &corev1.ConfigMap{
125					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
126					Data:       map[string]string{"k": "v"},
127				},
128				fetched: &corev1.ConfigMap{
129					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
130					Data:       map[string]string{"k": "v"},
131				},
132				wantChanged: false,
133			},
134			{
135				name: "Service identical",
136				desired: &corev1.Service{
137					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
138					Spec: corev1.ServiceSpec{
139						Type:     corev1.ServiceTypeClusterIP,
140						Ports:    []corev1.ServicePort{{Port: 443}},
141						Selector: map[string]string{"app": "x"},
142					},
143				},
144				fetched: &corev1.Service{
145					ObjectMeta: metav1.ObjectMeta{Labels: map[string]string{"a": "1"}},
146					Spec: corev1.ServiceSpec{
147						Type:     corev1.ServiceTypeClusterIP,
148						Ports:    []corev1.ServicePort{{Port: 443}},
149						Selector: map[string]string{"app": "x"},
150					},
151				},
152				wantChanged: false,
153			},
154			{
155				name:        "unsupported type (Pod) panics",
156				desired:     &corev1.Pod{ObjectMeta: metav1.ObjectMeta{Name: "a"}},
157				fetched:     &corev1.Pod{ObjectMeta: metav1.ObjectMeta{Name: "a"}},
158				wantPanic:   true,
159				panicSubstr: "unsupported",
160			},
161		}
162		for _, tt := range tests {
163			t.Run(tt.name, func(t *testing.T) {
164				if tt.wantPanic {
165					defer func() {
166						r := recover()
167						if r == nil {
168							t.Error("expected panic")
169						}
170						if msg := fmt.Sprintf("%v", r); tt.panicSubstr != "" && !strings.Contains(msg, tt.panicSubstr) {
171							t.Errorf("panic message = %q, want substring %q", msg, tt.panicSubstr)
172						}
173					}()
174				}
175				got := hasObjectChanged(tt.desired, tt.fetched)
176				if !tt.wantPanic && got != tt.wantChanged {
177					t.Errorf("hasObjectChanged() = %v, want %v", got, tt.wantChanged)
178				}
179			})
180		}
181	}
