## Implementation: Content-Hash-Triggered Rolling Restart for IstioCSR

### Summary of changes

The pattern mirrors trustmanager's `configmaps.go` → `deployments.go` flow:
1. Read the CNO-injected CA bundle ConfigMap from the operator namespace
2. SHA-256 hash the PEM content (not `resourceVersion`)
3. Stamp the hash as a pod template annotation on the IstioCSR Deployment
4. The existing `hasObjectChanged` check (with a new annotations comparison in `deploymentSpecModified`) acts as the idempotency guard — skipping the update when the hash is unchanged

---

### File 1: NEW — `pkg/controller/istiocsr/configmaps.go`

```go
package istiocsr

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	"sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/openshift/cert-manager-operator/api/operator/v1alpha1"
	"github.com/openshift/cert-manager-operator/pkg/controller/common"
)

// readAndHashTrustedCABundle reads the CNO-injected CA bundle ConfigMap from the
// operator namespace, computes a SHA-256 hash of the PEM data, and adds a watch
// label so that changes to the ConfigMap trigger reconciliation.
// Returns ("", nil) when the ConfigMap does not exist (graceful degradation for
// non-OpenShift clusters).
func (r *Reconciler) readAndHashTrustedCABundle(istiocsr *v1alpha1.IstioCSR) (string, error) {
	cm := &corev1.ConfigMap{}
	key := client.ObjectKey{
		Namespace: common.OperatorNamespace,
		Name:      common.TrustedCABundleConfigMapName,
	}
	if err := r.Get(r.ctx, key, cm); err != nil {
		if errors.IsNotFound(err) {
			r.log.V(4).Info("CNO-injected CA bundle ConfigMap not found, skipping hash annotation",
				"configmap", common.TrustedCABundleConfigMapName,
				"namespace", common.OperatorNamespace)
			return "", nil
		}
		return "", common.FromClientError(
			err,
			"failed to read CA bundle ConfigMap %q in namespace %q",
			common.TrustedCABundleConfigMapName, common.OperatorNamespace,
		)
	}

	caBundle, ok := cm.Data[common.TrustedCABundleKey]
	if !ok || caBundle == "" {
		return "", fmt.Errorf("CA bundle ConfigMap %q does not contain key %q",
			common.TrustedCABundleConfigMapName, common.TrustedCABundleKey)
	}

	if err := r.updateWatchLabel(cm, istiocsr); err != nil {
		return "", common.FromClientError(err,
			"failed to update watch label on CA bundle ConfigMap %s/%s",
			common.OperatorNamespace, common.TrustedCABundleConfigMapName)
	}

	return computeCABundleHash(caBundle), nil
}

// computeCABundleHash returns the SHA-256 hash of the CA bundle PEM content.
// The hash covers PEM content, not resourceVersion, so rolling restarts happen
// only when the actual certificate content changes.
func computeCABundleHash(caBundle string) string {
	hash := sha256.Sum256([]byte(caBundle))
	return hex.EncodeToString(hash[:])
}
```

