// updateCABundleHashAnnotation stamps the SHA-256 hash of the CNO-injected CA
// bundle as a pod template annotation. When the hash changes, Kubernetes treats
// it as a pod template change and triggers a rolling restart.
func updateCABundleHashAnnotation(deployment *appsv1.Deployment, caBundleHash string) {
	if caBundleHash == "" {
		return
	}
	if deployment.Spec.Template.Annotations == nil {
		deployment.Spec.Template.Annotations = make(map[string]string)
	}
	deployment.Spec.Template.Annotations[caBundleHashAnnotation] = caBundleHash
}
